/**
 * CRM funnel — kanban-style pipeline view (admin only).
 * Phase 5.2 / U!Clients-equivalent.
 */

import { useEffect, useState, useCallback } from 'react'
import PlatformShell from '../components/PlatformShell'
import { useToast } from '../hooks/useToast'
import {
  fetchLeads, fetchStageCounts, createLead, moveLeadStage,
  fetchLeadTouchpoints, addTouchpoint,
  STAGE_LABELS, STAGES_ORDER,
  type LeadDto, type LeadStage, type TouchpointDto, type TouchpointChannel,
} from '../api/crm'

const STAGE_COLOR: Record<LeadStage, string> = {
  new:             '#A9D8FF',
  contacted:       '#FFD43C',
  trial_scheduled: '#FF9454',
  trial_done:      '#FFB4C8',
  paid:            '#9FE8C7',
  active:          '#6B5CE7',
  paused:          '#999999',
  churned:         '#dc2626',
}

export default function CrmFunnel() {
  const { toast, show } = useToast()
  const [leads, setLeads] = useState<LeadDto[]>([])
  const [counts, setCounts] = useState<Record<LeadStage, number>>({
    new: 0, contacted: 0, trial_scheduled: 0, trial_done: 0, paid: 0, active: 0, paused: 0, churned: 0,
  })
  const [loading, setLoading] = useState(true)
  const [activeLead, setActiveLead] = useState<LeadDto | null>(null)
  const [touchpoints, setTouchpoints] = useState<TouchpointDto[]>([])
  const [showNewForm, setShowNewForm] = useState(false)
  const [newDraft, setNewDraft] = useState({ parentName: '', parentPhone: '', parentEmail: '', childName: '', childAge: '', track: 'python', notes: '' })

  const refresh = useCallback(() => {
    setLoading(true)
    Promise.all([fetchLeads({}), fetchStageCounts()])
      .then(([all, cnt]) => { setLeads(all); setCounts(cnt) })
      .catch(() => show('Ошибка загрузки лидов', 'error'))
      .finally(() => setLoading(false))
  }, [show])

  useEffect(() => { refresh() }, [refresh])

  useEffect(() => {
    if (!activeLead) { setTouchpoints([]); return }
    fetchLeadTouchpoints(activeLead.id).then(setTouchpoints).catch(() => { /* */ })
  }, [activeLead])

  async function handleMove(id: string, stage: LeadStage) {
    try {
      await moveLeadStage(id, stage)
      show('Статус обновлён', 'success')
      refresh()
      setActiveLead((prev) => prev?.id === id ? { ...prev, stage } : prev)
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    }
  }

  async function handleCreate() {
    try {
      await createLead({
        source: 'manual',
        parentName: newDraft.parentName || undefined,
        parentPhone: newDraft.parentPhone || undefined,
        parentEmail: newDraft.parentEmail || undefined,
        childName: newDraft.childName || undefined,
        childAge: newDraft.childAge ? parseInt(newDraft.childAge, 10) : undefined,
        track: newDraft.track || undefined,
        notes: newDraft.notes || undefined,
      })
      show('Лид создан', 'success')
      setShowNewForm(false)
      setNewDraft({ parentName: '', parentPhone: '', parentEmail: '', childName: '', childAge: '', track: 'python', notes: '' })
      refresh()
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    }
  }

  async function handleAddTouchpoint(channel: TouchpointChannel, body: string) {
    if (!activeLead || !body.trim()) return
    try {
      const tp = await addTouchpoint(activeLead.id, { channel, direction: 'outbound', body: body.trim() })
      setTouchpoints((prev) => [tp, ...prev])
      show('Записано', 'success')
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    }
  }

  return (
    <PlatformShell activeKey="admin">
      {toast && (
        <div role="status" aria-live="polite" style={{ position: 'fixed', top: 20, right: 20, zIndex: 9999, background: toast.kind === 'error' ? '#dc2626' : toast.kind === 'success' ? '#059669' : '#6b5ce7', color: '#fff', padding: '10px 20px', borderRadius: 12, fontSize: 14, fontWeight: 600 }}>{toast.msg}</div>
      )}

      <div className="kb-cover kb-cover--violet">
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 12 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <span style={{ fontSize: 36 }} aria-hidden>🎯</span>
            <div>
              <div className="eyebrow" style={{ color: 'rgba(255,255,255,0.7)' }}>CRM · Воронка лидов</div>
              <h1 className="h1" style={{ margin: 0, color: '#fff' }}>{leads.length} лидов в работе</h1>
            </div>
          </div>
          <button className="kb-btn" onClick={() => setShowNewForm((v) => !v)} style={{ background: '#fff', color: 'var(--violet)' }}>
            {showNewForm ? '✕ Отмена' : '+ Новый лид'}
          </button>
        </div>
      </div>

      <div style={{ padding: '20px 16px', maxWidth: 1400, margin: '0 auto' }}>

        {showNewForm && (
          <div className="kb-card" style={{ padding: 20, marginBottom: 20, display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: 12 }}>
            <input style={inp} placeholder="Имя родителя" value={newDraft.parentName} onChange={(e) => setNewDraft({ ...newDraft, parentName: e.target.value })} />
            <input style={inp} placeholder="Телефон" value={newDraft.parentPhone} onChange={(e) => setNewDraft({ ...newDraft, parentPhone: e.target.value })} />
            <input style={inp} placeholder="Email" value={newDraft.parentEmail} onChange={(e) => setNewDraft({ ...newDraft, parentEmail: e.target.value })} />
            <input style={inp} placeholder="Имя ребёнка" value={newDraft.childName} onChange={(e) => setNewDraft({ ...newDraft, childName: e.target.value })} />
            <input style={inp} placeholder="Возраст" type="number" value={newDraft.childAge} onChange={(e) => setNewDraft({ ...newDraft, childAge: e.target.value })} />
            <select style={inp} value={newDraft.track} onChange={(e) => setNewDraft({ ...newDraft, track: e.target.value })}>
              <option value="python">Python</option>
              <option value="scratch">Scratch</option>
              <option value="vibe">Vibe-coding</option>
            </select>
            <input style={{ ...inp, gridColumn: '1 / -1' }} placeholder="Заметки" value={newDraft.notes} onChange={(e) => setNewDraft({ ...newDraft, notes: e.target.value })} />
            <button className="kb-btn" style={{ gridColumn: '1 / -1', background: 'var(--violet)', color: '#fff' }} onClick={() => void handleCreate()}>Создать</button>
          </div>
        )}

        {/* Kanban grid */}
        <div style={{ display: 'flex', gap: 12, overflowX: 'auto', paddingBottom: 12 }}>
          {STAGES_ORDER.map((stage) => (
            <div
              key={stage}
              style={{ flex: '0 0 280px', display: 'flex', flexDirection: 'column', gap: 8 }}
            >
              <div style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '8px 12px', background: STAGE_COLOR[stage] + '33', borderRadius: 10, borderLeft: `4px solid ${STAGE_COLOR[stage]}` }}>
                <strong style={{ fontSize: 13 }}>{STAGE_LABELS[stage]}</strong>
                <span style={{ marginLeft: 'auto', fontSize: 12, color: 'var(--ink-soft)', fontWeight: 700 }}>{counts[stage] ?? 0}</span>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 6, minHeight: 100, maxHeight: '60vh', overflowY: 'auto' }}>
                {loading ? (
                  <div style={{ color: 'var(--ink-soft)', fontSize: 12, padding: 8 }}>Загрузка…</div>
                ) : (
                  leads.filter((l) => l.stage === stage).map((l) => (
                    <button
                      key={l.id}
                      onClick={() => setActiveLead(l)}
                      style={{ textAlign: 'left', padding: '10px 12px', background: '#fff', border: '1px solid var(--paper-3, #e5e2f0)', borderRadius: 10, cursor: 'pointer', fontSize: 13 }}
                    >
                      <div style={{ fontWeight: 700 }}>{l.childName ?? l.parentName ?? 'Без имени'}</div>
                      <div style={{ fontSize: 11, color: 'var(--ink-soft)', marginTop: 2 }}>
                        {l.track ?? '—'} · {l.parentPhone ?? l.parentEmail ?? '—'}
                      </div>
                    </button>
                  ))
                )}
              </div>
            </div>
          ))}
        </div>

        {/* Lead detail panel */}
        {activeLead && (
          <div onClick={() => setActiveLead(null)} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', zIndex: 1000, display: 'flex', justifyContent: 'flex-end' }}>
            <div onClick={(e) => e.stopPropagation()} style={{ width: 480, maxWidth: '90vw', height: '100vh', overflowY: 'auto', background: 'var(--paper)', padding: 24, boxShadow: '-10px 0 40px rgba(0,0,0,0.2)' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 12 }}>
                <div>
                  <div className="eyebrow">{STAGE_LABELS[activeLead.stage]}</div>
                  <h2 style={{ margin: '6px 0 4px', fontSize: 20, fontWeight: 800 }}>
                    {activeLead.childName ?? activeLead.parentName ?? 'Лид'}
                  </h2>
                  <div style={{ fontSize: 12, color: 'var(--ink-soft)' }}>
                    Источник: {activeLead.source} · создан {new Date(activeLead.createdAt).toLocaleDateString('ru-RU')}
                  </div>
                </div>
                <button onClick={() => setActiveLead(null)} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: 20 }}>✕</button>
              </div>

              <section style={{ marginTop: 20, fontSize: 14 }}>
                <div className="eyebrow">Контакты</div>
                <div style={{ marginTop: 6, lineHeight: 1.7 }}>
                  <div>Родитель: {activeLead.parentName ?? '—'}</div>
                  <div>Телефон: {activeLead.parentPhone ?? '—'}</div>
                  <div>Email: {activeLead.parentEmail ?? '—'}</div>
                  <div>Ребёнок: {activeLead.childName ?? '—'} ({activeLead.childAge ?? '?'} лет)</div>
                  <div>Трек: {activeLead.track ?? '—'}</div>
                  {activeLead.crmUrl && (
                    <div><a href={activeLead.crmUrl} target="_blank" rel="noreferrer">→ открыть в CRM</a></div>
                  )}
                </div>
              </section>

              {activeLead.notes && (
                <section style={{ marginTop: 16 }}>
                  <div className="eyebrow">Заметки</div>
                  <div style={{ marginTop: 6, fontSize: 13, color: 'var(--ink-soft)' }}>{activeLead.notes}</div>
                </section>
              )}

              <section style={{ marginTop: 20 }}>
                <div className="eyebrow">Перевести в стадию</div>
                <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', marginTop: 8 }}>
                  {STAGES_ORDER.filter((s) => s !== activeLead.stage).map((s) => (
                    <button
                      key={s}
                      onClick={() => void handleMove(activeLead.id, s)}
                      style={{
                        padding: '4px 10px', fontSize: 12, borderRadius: 999,
                        background: STAGE_COLOR[s] + '22', border: `1px solid ${STAGE_COLOR[s]}`,
                        cursor: 'pointer', fontWeight: 600,
                      }}
                    >
                      → {STAGE_LABELS[s]}
                    </button>
                  ))}
                </div>
              </section>

              <TouchpointForm onSubmit={handleAddTouchpoint} />

              <section style={{ marginTop: 20 }}>
                <div className="eyebrow">История общения</div>
                {touchpoints.length === 0 ? (
                  <div style={{ marginTop: 8, fontSize: 13, color: 'var(--ink-soft)' }}>Ещё ничего не записано</div>
                ) : (
                  <div style={{ marginTop: 12, display: 'flex', flexDirection: 'column', gap: 8 }}>
                    {touchpoints.map((tp) => (
                      <div key={tp.id} style={{ padding: 10, background: 'var(--paper-2, #f9f8ff)', borderRadius: 10, fontSize: 13 }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11, color: 'var(--ink-soft)' }}>
                          <span>{tp.channel} · {tp.direction === 'inbound' ? '← вх' : '→ исх'}</span>
                          <span>{new Date(tp.occurredAt).toLocaleString('ru-RU', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' })}</span>
                        </div>
                        {tp.subject && <div style={{ fontWeight: 700, marginTop: 4 }}>{tp.subject}</div>}
                        <div style={{ marginTop: 4 }}>{tp.body}</div>
                      </div>
                    ))}
                  </div>
                )}
              </section>
            </div>
          </div>
        )}
      </div>
    </PlatformShell>
  )
}

function TouchpointForm({ onSubmit }: { onSubmit: (channel: TouchpointChannel, body: string) => void | Promise<void> }) {
  const [channel, setChannel] = useState<TouchpointChannel>('phone')
  const [body, setBody] = useState('')

  return (
    <section style={{ marginTop: 20 }}>
      <div className="eyebrow">Добавить отметку</div>
      <div style={{ display: 'flex', gap: 8, marginTop: 8 }}>
        <select value={channel} onChange={(e) => setChannel(e.target.value as TouchpointChannel)} style={{ ...inp, width: 'auto' }}>
          <option value="phone">📞 Звонок</option>
          <option value="email">✉ Email</option>
          <option value="sms">📱 SMS</option>
          <option value="telegram">💬 Telegram</option>
          <option value="whatsapp">📲 WhatsApp</option>
          <option value="in_person">👋 Очно</option>
        </select>
      </div>
      <textarea value={body} onChange={(e) => setBody(e.target.value)} placeholder="О чём договорились…" rows={3} style={{ ...inp, marginTop: 8 }} />
      <button
        className="kb-btn"
        style={{ marginTop: 8, background: 'var(--violet)', color: '#fff' }}
        disabled={!body.trim()}
        onClick={async () => { await onSubmit(channel, body); setBody('') }}
      >
        Записать
      </button>
    </section>
  )
}

const inp: React.CSSProperties = {
  width: '100%', padding: '8px 12px', borderRadius: 10,
  border: '1px solid var(--paper-3, #e5e2f0)', fontSize: 14, fontFamily: 'inherit',
  background: '#fff', color: '#15141b', boxSizing: 'border-box',
}
